// Script Continued Below
function onLoad() {
	if(!g_scratchpad.userHasPersonalTemplateRights){
		g_form.removeOption('process_level', 'my_process');
	}
	if(!g_scratchpad.userHasOUTemplateRights){
		g_form.removeOption('process_level', 'ou_process');
	}
	if(!g_scratchpad.userHasGlobalTemplateRights){
		g_form.removeOption('process_level', 'global_process');
	}
}
